// EVENT (crosses command→read model boundary):
public record OrderFilledEvent(String merchantId, String symbol, int quantity, BigDecimal price) {}

// READ MODEL STORE (in-memory for demo; real = DB/Redis):
@Service
class PortfolioStore {
    private final Map<String, BigDecimal> portfolioValues = new HashMap<>();
    void addValue(String merchantId, BigDecimal value){
        portfolioValues.merge(merchantId, value, BigDecimal::add);
    }
    BigDecimal getValue(String merchantId){
        return portfolioValues.getOrDefault(merchantId, BigDecimal.ZERO);
    }
}

// PROJECTION: listens for events, updates read model
@Service
public class PortfolioProjection {
    private final PortfolioStore store;
    PortfolioProjection(PortfolioStore s){store=s;}

    @EventListener
    @Async  // async: projection doesn't block command handler thread
    public void on(OrderFilledEvent event) {
        BigDecimal tradeValue = event.price().multiply(BigDecimal.valueOf(event.quantity()));
        store.addValue(event.merchantId(), tradeValue);
    }
}

@Configuration @EnableAsync
class AsyncConfig {}

@SpringBootTest
class ProjectionTest {
    @Autowired ApplicationEventPublisher pub;
    @Autowired PortfolioStore store;

    @Test void projection_updatesReadModel() throws InterruptedException {
        // Simulate trade filled event:
        pub.publishEvent(new OrderFilledEvent("MRC-TEST","TCS",100,new BigDecimal("3500")));
        TimeUnit.MILLISECONDS.sleep(200); // wait for async projection
        BigDecimal val=store.getValue("MRC-TEST");
        assertEquals(new BigDecimal("350000"),val); // 100 × 3500
    }
}

