import org.junit.jupiter.api.*;
import java.util.Set;

class CommandValidationException extends RuntimeException {
    public CommandValidationException(String msg){super(msg);}
}

@Service
class ValidatingOrderCommandHandler {
    private static final Set<String> VALID_TYPES=Set.of("BUY","SELL","LIMIT","SL");

    public String handle(PlaceOrderCommand cmd) {
        // Validate BEFORE any DB write:
        validate(cmd);
        // If validation passes: proceed with persistence
        return "ORD-"+cmd.symbol()+"-"+System.nanoTime();
    }

    private void validate(PlaceOrderCommand cmd) {
        if(cmd.symbol()==null||cmd.symbol().isBlank())
            throw new CommandValidationException("symbol is required");
        if(cmd.quantity()<=0||cmd.quantity()>10000)
            throw new CommandValidationException("quantity must be 1-10000, got: "+cmd.quantity());
        if(!VALID_TYPES.contains(cmd.orderType()))
            throw new CommandValidationException("orderType must be one of "+VALID_TYPES+", got: "+cmd.orderType());
    }
}

@SpringBootTest
class CommandValidationTest {
    @Autowired ValidatingOrderCommandHandler handler;

    @Test void valid_passes(){
        String id=handler.handle(new PlaceOrderCommand("MRC-001","RELIANCE",10,"BUY"));
        assertTrue(id.startsWith("ORD-RELIANCE-"));
    }
    @Test void blankSymbol_throws(){
        var ex=assertThrows(CommandValidationException.class,
            ()->handler.handle(new PlaceOrderCommand("MRC-001","",10,"BUY")));
        assertTrue(ex.getMessage().contains("symbol is required"));
    }
    @Test void badQuantity_throws(){
        assertThrows(CommandValidationException.class,
            ()->handler.handle(new PlaceOrderCommand("MRC-001","RELIANCE",-5,"BUY")));
    }
}

