// AXON FRAMEWORK CQRS:
// pom.xml: axon-spring-boot-starter
// Axon provides: command bus, event bus, query bus, event store
// Much less boilerplate than manual CQRS

import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.math.BigDecimal;

// Manual CQRS (without Axon) — show the equivalent:

// @Aggregate equivalent (domain aggregate):
public class ZerodhaOrderAggregate {
    private String orderId;
    private String merchantId;
    private String symbol;
    private String status;

    // CommandHandler equivalent:
    public String handlePlaceOrder(PlaceOrderCommand cmd) {
        if(cmd.symbol()==null) throw new IllegalArgumentException("Symbol required");
        this.orderId="ORD-"+System.nanoTime();
        this.merchantId=cmd.merchantId();
        this.symbol=cmd.symbol();
        this.status="PLACED";
        return orderId;
    }

    // EventSourcingHandler equivalent — applies event to rebuild state:
    public void applyOrderPlaced(String id, String symbol) {
        this.orderId=id;
        this.symbol=symbol;
        this.status="PLACED";
    }

    String getStatus(){return status;}
    String getSymbol(){return symbol;}
}

// QueryHandler equivalent:
@Service
class ZerodhaPortfolioQueryHandler {
    public PortfolioView handle(GetPortfolioQuery q) {
        return new PortfolioView(q.merchantId(), BigDecimal.ZERO, 0);
    }
}

// WHY AXON:
// Axon: command bus, event bus, query bus out of the box
//   @Aggregate: manages state and command handling in one place
//   @CommandHandler: registered automatically with command bus
//   @QueryHandler: registered with query bus
//   Event store: persists all events (basis for Event Sourcing)
// Manual CQRS: must wire command bus, event bus, handlers yourself
// Axon: production-grade, distributed (Axon Server) for microservices

@SpringBootTest
class AxonEquivalentTest {
    @Test void aggregate_handlesCommand(){
        ZerodhaOrderAggregate agg=new ZerodhaOrderAggregate();
        String id=agg.handlePlaceOrder(new PlaceOrderCommand("MRC-001","RELIANCE",10,"BUY"));
        assertTrue(id.startsWith("ORD-"));
        assertEquals("PLACED",agg.getStatus());
    }
}

