    public String handle(PlaceOrderCommand cmd) throws Exception {
        String id="ORD-"+System.nanoTime();
        // Publish to Kafka (durable, survives pod restarts):
        String payload=mapper.writeValueAsString(
            new KOrderFilledEvent(cmd.merchantId(),cmd.symbol(),cmd.quantity()));
        kafka.send("orders.filled",cmd.merchantId(),payload); // key=merchantId for partition ordering
        return id;
    }
}

@Service
class KafkaPortfolioProjection {
    private java.util.Map<String,Integer> volumes=new java.util.HashMap<>();
    @KafkaListener(topics="orders.filled",groupId="portfolio-service")
    public void on(String eventJson) throws Exception {
        ObjectMapper m=new ObjectMapper();
        KOrderFilledEvent e=m.readValue(eventJson,KOrderFilledEvent.class);
        volumes.merge(e.merchantId(),e.qty(),Integer::sum);
    }
    int getVolume(String m){return volumes.getOrDefault(m,0);}
}

// WHY KAFKA VS SPRING EVENTS:
// Spring ApplicationEvent: in-process only (same JVM/pod)
//   Good for: single-service CQRS (command and query in same pod)
//   Bad for: microservices (OrderService and PortfolioService separate pods)
// Kafka: durable message bus (survives pod restarts)
//   Good for: microservices CQRS (services in separate pods/processes)
//   Offset commit: projection can replay events from beginning if needed
//   Consumer groups: multiple portfolio-service instances, each gets all events
// Rule: same JVM → Spring Events. Microservices → Kafka/RabbitMQ

