import org.springframework.stereotype.*;
import org.springframework.context.event.*;
import org.springframework.context.ApplicationEventPublisher;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.math.BigDecimal;
import java.util.*;

record M24PlaceCmd(String merchantId,String symbol,int quantity,String orderType){}
record M24PortfolioQuery(String merchantId){}
record M24PortfolioView(String merchantId,BigDecimal value){}
record M24OrderEvent(String merchantId,String symbol,int qty,BigDecimal price){}

@Service class M24CmdHandler {
    private final ApplicationEventPublisher pub;
    M24CmdHandler(ApplicationEventPublisher p){pub=p;}
    public String handle(M24PlaceCmd cmd){
        if(cmd.symbol()==null||cmd.symbol().isBlank()) throw new IllegalArgumentException("symbol required");
        if(cmd.quantity()<=0) throw new IllegalArgumentException("quantity must be positive");
        String id="ORD-"+System.nanoTime();
        pub.publishEvent(new M24OrderEvent(cmd.merchantId(),cmd.symbol(),cmd.quantity(),new BigDecimal("100")));
        return id;
    }
}

@Service class M24Projection {
    private final Map<String,BigDecimal> store=new HashMap<>();
    @EventListener public void on(M24OrderEvent e){
        store.merge(e.merchantId(),e.price().multiply(BigDecimal.valueOf(e.qty())),BigDecimal::add);
    }
    public M24PortfolioView query(M24PortfolioQuery q){
        return new M24PortfolioView(q.merchantId(),store.getOrDefault(q.merchantId(),BigDecimal.ZERO));
    }
}

